# Simplified PagedAttention block allocator
class BlockAllocator:
    """Manages a pool of fixed-size KV-cache blocks."""

    def __init__(self, num_blocks: int, block_size: int = 16):
        self.block_size = block_size
        self.free: set[int] = set(range(num_blocks))
        self.ref_count: dict[int, int] = {}   # block_id -> reference count

    def allocate(self) -> int:
        if not self.free:
            raise MemoryError("KV-cache OOM — preempt a sequence")
        block_id = self.free.pop()
        self.ref_count[block_id] = 1
        return block_id

    def fork(self, block_id: int) -> int:
        """Share a block (e.g. for parallel sampling / beam search)."""
        self.ref_count[block_id] += 1
        return block_id

    def free_block(self, block_id: int) -> None:
        self.ref_count[block_id] -= 1
        if self.ref_count[block_id] == 0:
            del self.ref_count[block_id]
            self.free.add(block_id)

